// 前端：Socket.IO 连接与事件处理
import { io, type Socket } from 'socket.io-client';
import type { Player, Obstacle, JoinedPayload, PlayerInput, Bullet } from '../../shared/types';

export interface GameSocketEvents {
  onConnected: () => void;
  onJoined: (data: JoinedPayload) => void;
  onPlayerJoined: (player: Player) => void;
  onPlayerLeft: (id: string) => void;
  onGameState: (players: Player[]) => void;
  onBulletFired: (bullet: Bullet) => void;
  onObstacleHit: (payload: { obstacleId: string; hp: number; maxHp: number }) => void;
  onObstacleDestroyed: (payload: { obstacleId: string }) => void;
  onSelectionUpdated: (payload: { selectedUnitId: string; selectedSkillIndex: number }) => void;
  onDisconnect: () => void;
}

export class GameSocket {
  private socket: Socket | null = null;
  private events: GameSocketEvents;

  constructor(events: GameSocketEvents) {
    this.events = events;
  }

  connect(): void {
    this.socket = io(location.origin, {
      transports: ['polling', 'websocket'],
      reconnection: true,
      reconnectionDelay: 800,
      timeout: 15000
    });

    this.socket.on('connect', () => {
      this.events.onConnected();
    });

    this.socket.on('joined', (data: JoinedPayload) => {
      this.events.onJoined(data);
    });

    this.socket.on('playerJoined', (player: Player) => {
      this.events.onPlayerJoined(player);
    });

    this.socket.on('playerLeft', (id: string) => {
      this.events.onPlayerLeft(id);
    });

    this.socket.on('gameState', (players: Player[]) => {
      this.events.onGameState(players);
    });

    this.socket.on('bulletFired', (bullet: Bullet) => {
      this.events.onBulletFired(bullet);
    });

    this.socket.on('obstacleHit', (payload: { obstacleId: string; hp: number; maxHp: number }) => {
      this.events.onObstacleHit(payload);
    });

    this.socket.on('obstacleDestroyed', (payload: { obstacleId: string }) => {
      this.events.onObstacleDestroyed(payload);
    });

    this.socket.on(
      'selectionUpdated',
      (payload: { selectedUnitId: string; selectedSkillIndex: number }) => {
        this.events.onSelectionUpdated(payload);
      }
    );

    this.socket.on('disconnect', () => {
      this.events.onDisconnect();
    });
  }

  joinRoom(roomId: string, playerName: string): void {
    this.socket?.emit('joinRoom', { roomId, playerName });
  }

  sendInput(input: PlayerInput): void {
    this.socket?.emit('playerInput', input);
  }

  sendBulletFire(payload: {
    vx: number;
    vy: number;
    x: number;
    y: number;
    charge: number;
  }): void {
    this.socket?.emit('bulletFire', payload);
  }

  sendUnitSelect(unitId: string): void {
    this.socket?.emit('unitSelect', { unitId });
  }

  sendSkillSelect(index: number): void {
    this.socket?.emit('skillSelect', { index });
  }

  isConnected(): boolean {
    return this.socket?.connected ?? false;
  }

  disconnect(): void {
    this.socket?.disconnect();
    this.socket = null;
  }
}
